1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const FIRST_INSURANCE_SURCHARGE = 1.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const PROCESSING_FEE = 5;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
38	
39	// Base premium of a single item (main item or one component).
40	const itemBase = (item: Item): number =>
41	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
42	
43	// Curse adds 50% of the affected item's base premium.
44	const curseSurcharge = (items: Item[]): number =>
45	  sum(items.filter((item) => item.cursed).map((item) => CURSE_SURCHARGE_RATE * itemBase(item)));
46	
47	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
48	const enchantmentSurcharge = (items: Item[]): number =>
49	  sum(
50	    items
51	      .filter((item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
52	      .map((item) => HIGH_ENCHANTMENT_SURCHARGE_RATE * itemBase(item)),
53	  );
54	
55	// Base premium for `count` alike components: a group of exactly 3 forms a
56	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
57	// COMPONENT_PREMIUM.
58	const componentGroupPremium = (count: number): number =>
59	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
60	
61	// Count how many alike components of each type appear (e.g. { rune: 2 }).
62	const countByType = (items: Item[]): Map<string, number> =>
63	  items.reduce((counts, item) => {
64	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
65	    return counts;
66	  }, new Map<string, number>());
67	
68	const mainItemsPremium = (items: Item[]): number =>
69	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
70	
71	const componentsPremium = (items: Item[]): number =>
72	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
73	
74	const basePremium = (items: Item[]): number =>
75	  mainItemsPremium(items) + componentsPremium(items);
76	
77	// Round up to a whole number in MHPCO's favour, guarding against
78	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
79	// to 6 decimal places first.
80	const FLOAT_GUARD_PRECISION = 1e6;
81	const roundUpToWhole = (value: number): number =>
82	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
83	
84	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
85	  const results = scenario.steps.map((step) => {
86	    const base = basePremium(step.items);
87	    const premium =
88	      base * FIRST_INSURANCE_SURCHARGE +
89	      curseSurcharge(step.items) +
90	      enchantmentSurcharge(step.items) +
91	      PROCESSING_FEE;
92	    return { premium: roundUpToWhole(premium) };
93	  });
94	  return { results };
95	};
